const staticData = $getWorkflowStaticData('global');
const rows = $input.all().map(i => i.json);

// Save high-water mark — use the latest created_at from this batch
// Preserve raw Postgres string to keep microsecond precision
if (rows.length > 0) {
  const maxCreatedAt = rows.reduce((max, r) => {
    return (r.created_at && r.created_at > max) ? r.created_at : max;
  }, '');
  if (maxCreatedAt) {
    // Bump by 1ms to clear microsecond precision gap:
    // n8n Postgres node truncates timestamps to milliseconds,
    // but Postgres stores microseconds. Without this bump,
    // the same row re-matches on every hourly run.
    const d = new Date(maxCreatedAt);
    d.setMilliseconds(d.getMilliseconds() + 1);
    staticData.lastProcessedAt = d.toISOString();
  }
}

// Group by person_id first
const byPerson = {};
for (const row of rows) {
  const pid = row.person_id;
  if (!pid) continue;
  if (!byPerson[pid]) byPerson[pid] = [];
  byPerson[pid].push(row);
}

// Then batch each person's messages (max 20 per batch)
const output = [];
for (const [pid, msgs] of Object.entries(byPerson)) {
  for (let i = 0; i < msgs.length; i += 20) {
    const batch = msgs.slice(i, i + 20);
    output.push({
      json: {
        messages: batch,
        source_platform: batch[0]?.source_platform || 'discord',
        source_privacy: batch[0]?.source_privacy || 'public',
        person_id: pid
      }
    });
  }
}
return output;

const result = $input.first().json;
const upstream = $('Build Extraction Request').first().json;

// Get batch date from Group Messages — latest created_at as fallback event_date
const groupMsgs = $('Group Messages').first().json.messages || [];
let batchDate = null;
if (groupMsgs.length > 0) {
  const latest = groupMsgs.reduce((a, b) =>
    new Date(a.created_at) > new Date(b.created_at) ? a : b
  );
  if (latest.created_at) {
    const d = new Date(latest.created_at);
    // Format in user's timezone (America/New_York)
    const parts = d.toLocaleDateString('en-US', {
      timeZone: 'America/New_York',
      month: 'short',
      day: 'numeric'
    }).split(' ');
    batchDate = parts.join(' ');
  }
}

let observations = [];
try {
  let text = result.choices?.[0]?.message?.content || '[]';
  text = text.replace(/^```(?:json)?\n?/m, '').replace(/\n?```$/m, '').trim();
  observations = JSON.parse(text);
} catch(e) { observations = []; }

if (!Array.isArray(observations) || observations.length === 0) {
  return [{ json: { skip: true } }];
}

return observations.map(obs => {
  const event_date = obs.event_date || batchDate;

  const new_content = (obs.key_label || '') + ': ' + (obs.value_text || '')
    + (obs.context ? ' -- ' + obs.context : '')
    + (event_date ? ' (' + event_date + ')' : '');

  return {
    json: {
      key_label: obs.key_label,
      value_text: obs.value_text,
      context: obs.context || null,
      event_date: event_date,
      new_content: new_content,
      privacy_level: obs.privacy_level || upstream.source_privacy || 'public',
      asserted_by: obs.asserted_by || 'self',
      confidence: obs.confidence !== undefined ? obs.confidence : 0.5,
      source_platform: upstream.source_platform || 'discord',
      person_id: upstream.person_id,
      message_ids: upstream.message_ids
    }
  };
});

// Merge each embedding result with its corresponding observation context (by index)
const embedItems = $input.all();
const ctxItems = $('Pre-Embed Context').all();

return embedItems.map((embedItem, idx) => {
  const embedding = embedItem.json.data?.[0]?.embedding || [];
  const embeddingStr = '[' + embedding.join(',') + ']';
  const ctxData = ctxItems[idx]?.json || {};

  return {
    json: {
      person_id: ctxData.person_id,
      content: ctxData.new_content,
      key_label: ctxData.key_label,
      context: ctxData.context,
      event_date: ctxData.event_date,
      embedding_str: embeddingStr,
      source_platform: ctxData.source_platform || 'discord',
      privacy_level: ctxData.privacy_level || 'public',
      action: ctxData.action,
      existing_id: ctxData.existing_id
    }
  };
});

const dupResults = $input.all();
const obsItems = $('Parse Observations').all();

return dupResults.map((dupItem, idx) => {
  const dupResult = dupItem.json;
  const obs = obsItems[idx]?.json || {};

  // Sentinel row check (UNION ALL pattern)
  const hasDuplicate = dupResult.id != null;

  const baseFields = {
    person_id: obs.person_id,
    key_label: obs.key_label,
    value_text: obs.value_text,
    context: obs.context || null,
    event_date: obs.event_date || null,
    privacy_level: obs.privacy_level || 'public',
    source_platform: obs.source_platform || 'discord',
    new_content: obs.new_content,
    confidence: obs.confidence !== undefined ? obs.confidence : 0.5,
    asserted_by: obs.asserted_by || 'self'
  };

  if (hasDuplicate) {
    const existingValue = (dupResult.content || '').split(':').slice(1).join(':').trim();
    const existingCore = existingValue.split('--')[0].trim().toLowerCase();
    const newValue = (obs.value_text || '').toLowerCase();

    const valueChanged = existingCore !== newValue
      && !existingCore.includes(newValue)
      && !newValue.includes(existingCore);

    return {
      json: {
        action: valueChanged ? 'replace' : 'update',
        existing_id: dupResult.id,
        ...baseFields
      },
      pairedItem: { item: idx }
    };
  } else {
    return {
      json: {
        action: 'insert',
        existing_id: null,
        ...baseFields
      },
      pairedItem: { item: idx }
    };
  }
});

// Identity pass-through — preserves observation context for Prepare Insert Data
// Items arrive from Soft Delete (replace) and direct bypass (insert)
return $input.all().map((item, idx) => ({
  json: { ...item.json },
  pairedItem: { item: idx }
}));

const staticData = $getWorkflowStaticData('global');
// Default: 2 hours ago if no previous run recorded
const defaultTime = new Date(Date.now() - 2 * 60 * 60 * 1000).toISOString();
const lastProcessedAt = staticData.lastProcessedAt || defaultTime;
return [{ json: { last_processed_at: lastProcessedAt } }];

